# solution.py
"""
MultiAgentBudgetOptimizer
=========================

A collaborative budgeting tool that lets multiple users share a single pool of
category budgets, record expenses against those categories, view a consolidated
financial dashboard, and receive optimization suggestions (budget reallocation,
spending reductions, and savings-goal guidance).

Design notes
------------
* A single optimizer owns the shared state: users, per-category budget limits,
  a flat list of expense records, and incrementally-maintained roll-ups for
  per-category and per-user spending.
* Category names are case-insensitive (keyed by the lower-cased, stripped form)
  while the first-seen display spelling is preserved for reporting.
* All money is rounded to cents using round-half-up via ``decimal.Decimal`` to
  avoid binary floating-point surprises.
* Errors form a small hierarchy rooted at ``BudgetError``; the leaf types also
  derive from the closest built-in (``ValueError`` / ``LookupError``) so callers
  may catch either the domain type or the familiar built-in.

Standard library only. Python 3.12. ASCII only.
"""

from __future__ import annotations

import unittest
from decimal import Decimal, ROUND_HALF_UP

__all__ = [
    "MultiAgentBudgetOptimizer",
    "BudgetError",
    "ValidationError",
    "NotFoundError",
    "DuplicateError",
]


# --------------------------------------------------------------------------- #
# Errors
# --------------------------------------------------------------------------- #
class BudgetError(Exception):
    """Base class for every MultiAgentBudgetOptimizer error."""


class ValidationError(BudgetError, ValueError):
    """Raised when an argument fails validation."""


class NotFoundError(BudgetError, LookupError):
    """Raised when a referenced user or category does not exist."""


class DuplicateError(BudgetError, ValueError):
    """Raised when creating an entity that already exists."""


# --------------------------------------------------------------------------- #
# Module helpers
# --------------------------------------------------------------------------- #
_CENT = Decimal("0.01")


def _is_number(value):
    """True for real int/float values, explicitly excluding bool."""
    return isinstance(value, (int, float)) and not isinstance(value, bool)


def _money(value):
    """Round a numeric value to cents (round-half-up) and return a float."""
    if not _is_number(value):
        raise ValidationError("amount must be a real number")
    return float(Decimal(str(value)).quantize(_CENT, rounding=ROUND_HALF_UP))


def _fmt_money(value):
    """Render a numeric value as a fixed two-decimal currency string."""
    return "$%0.2f" % float(value)


def _norm_category(category):
    """Validate and normalize a category to its case-insensitive key."""
    if not isinstance(category, str):
        raise ValidationError("category must be a string")
    key = category.strip().lower()
    if not key:
        raise ValidationError("category must be a non-empty string")
    return key


# --------------------------------------------------------------------------- #
# Core application
# --------------------------------------------------------------------------- #
class MultiAgentBudgetOptimizer:
    """Collaboratively manage and optimize a shared, multi-user budget."""

    def __init__(self):
        self._users = {}            # name -> {"name": name}
        self._budgets = {}          # key  -> {"name": display, "limit": float}
        self._expenses = []         # list of {"user", "category", "amount"}
        self._cat_spent = {}        # key  -> float (sum of expenses in category)
        self._user_spent = {}       # name -> float (sum of a user's expenses)
        self._savings_goal = 0.0

    # ----------------------------------------------------------------- #
    # User management
    # ----------------------------------------------------------------- #
    def add_user(self, name):
        """Register a new user. Returns the stored (stripped) name."""
        if not isinstance(name, str):
            raise ValidationError("user name must be a string")
        clean = name.strip()
        if not clean:
            raise ValidationError("user name must be a non-empty string")
        if clean in self._users:
            raise DuplicateError("user already exists: %s" % clean)
        self._users[clean] = {"name": clean}
        self._user_spent[clean] = 0.0
        return clean

    def remove_user(self, name):
        """Remove a user and purge all of their recorded spending."""
        clean = self._require_user(name)
        kept = []
        for exp in self._expenses:
            if exp["user"] == clean:
                cat = exp["category"]
                self._cat_spent[cat] = _money(self._cat_spent.get(cat, 0.0) - exp["amount"])
            else:
                kept.append(exp)
        self._expenses = kept
        del self._users[clean]
        self._user_spent.pop(clean, None)
        return clean

    def has_user(self, name):
        """True if a user with this (stripped) name exists."""
        return isinstance(name, str) and name.strip() in self._users

    def users(self):
        """Sorted list of registered user names."""
        return sorted(self._users)

    def get_user(self, name):
        """Return a per-user summary; alias of :meth:`user_view`."""
        return self.user_view(name)

    def user_view(self, name):
        """Detailed view of a single user's spending."""
        clean = self._require_user(name)
        total = self.total_spent()
        amount = _money(self._user_spent.get(clean, 0.0))
        by_category = {}
        count = 0
        for exp in self._expenses:
            if exp["user"] == clean:
                disp = self._display(exp["category"])
                by_category[disp] = _money(by_category.get(disp, 0.0) + exp["amount"])
                count += 1
        return {
            "name": clean,
            "total_spent": amount,
            "share": round((amount / total) if total > 0 else 0.0, 6),
            "by_category": by_category,
            "expense_count": count,
        }

    def _require_user(self, name):
        if not isinstance(name, str):
            raise ValidationError("user name must be a string")
        clean = name.strip()
        if clean not in self._users:
            raise NotFoundError("unknown user: %s" % clean)
        return clean

    # ----------------------------------------------------------------- #
    # Budget management
    # ----------------------------------------------------------------- #
    def set_budget(self, category, amount):
        """Create or replace the spending limit for a category."""
        key = _norm_category(category)
        if not _is_number(amount):
            raise ValidationError("budget amount must be a real number")
        if amount < 0:
            raise ValidationError("budget amount must be non-negative")
        limit = _money(amount)
        if key in self._budgets:
            self._budgets[key]["limit"] = limit
        else:
            self._budgets[key] = {"name": category.strip(), "limit": limit}
            self._cat_spent.setdefault(key, 0.0)
        return limit

    def get_budget(self, category):
        """Return the limit for a category (case-insensitive)."""
        key = self._require_category(category)
        return self._budgets[key]["limit"]

    def has_budget(self, category):
        """True if a budget exists for the category."""
        try:
            key = _norm_category(category)
        except ValidationError:
            return False
        return key in self._budgets

    def adjust_budget(self, category, delta):
        """Increase or decrease a category limit by ``delta``."""
        key = self._require_category(category)
        if not _is_number(delta):
            raise ValidationError("delta must be a real number")
        new_limit = _money(self._budgets[key]["limit"] + delta)
        if new_limit < 0:
            raise ValidationError("resulting budget would be negative")
        self._budgets[key]["limit"] = new_limit
        return new_limit

    def remove_budget(self, category):
        """Remove a category limit and purge any expenses recorded against it."""
        key = self._require_category(category)
        kept = []
        for exp in self._expenses:
            if exp["category"] == key:
                user = exp["user"]
                self._user_spent[user] = _money(self._user_spent.get(user, 0.0) - exp["amount"])
            else:
                kept.append(exp)
        self._expenses = kept
        self._cat_spent.pop(key, None)
        name = self._budgets[key]["name"]
        del self._budgets[key]
        return name

    def categories(self):
        """Sorted list of category display names."""
        return [self._budgets[k]["name"] for k in sorted(self._budgets)]

    def total_budget(self):
        """Sum of every category limit."""
        return _money(sum(b["limit"] for b in self._budgets.values()))

    def _require_category(self, category):
        key = _norm_category(category)
        if key not in self._budgets:
            raise NotFoundError("unknown category: %s" % category)
        return key

    def _display(self, key):
        return self._budgets[key]["name"] if key in self._budgets else key

    # ----------------------------------------------------------------- #
    # Expenses
    # ----------------------------------------------------------------- #
    def add_expense(self, user, category, amount):
        """Record an expense by ``user`` against ``category``."""
        clean_user = self._require_user(user)
        key = self._require_category(category)
        if not _is_number(amount):
            raise ValidationError("expense amount must be a real number")
        if amount <= 0:
            raise ValidationError("expense amount must be positive")
        amt = _money(amount)
        self._expenses.append({"user": clean_user, "category": key, "amount": amt})
        self._cat_spent[key] = _money(self._cat_spent.get(key, 0.0) + amt)
        self._user_spent[clean_user] = _money(self._user_spent.get(clean_user, 0.0) + amt)
        return amt

    def category_spent(self, category):
        """Total recorded spending in a category."""
        key = self._require_category(category)
        return _money(self._cat_spent.get(key, 0.0))

    def category_remaining(self, category):
        """Remaining headroom (limit minus spent); negative when over budget."""
        key = self._require_category(category)
        return _money(self._budgets[key]["limit"] - self._cat_spent.get(key, 0.0))

    def is_over_budget(self, category):
        """True when spending in a category exceeds its limit."""
        return self.category_remaining(category) < 0

    # ----------------------------------------------------------------- #
    # Totals, contributions and savings goal
    # ----------------------------------------------------------------- #
    def total_spent(self):
        """Total recorded spending across all categories."""
        return _money(sum(self._cat_spent.values()))

    def remaining_budget(self):
        """Total budget minus total spending."""
        return _money(self.total_budget() - self.total_spent())

    def member_contributions(self):
        """Per-user contribution amounts and shares of total spending."""
        total = self.total_spent()
        out = {}
        for name in self._users:
            amount = _money(self._user_spent.get(name, 0.0))
            share = (amount / total) if total > 0 else 0.0
            out[name] = {"amount": amount, "share": round(share, 6)}
        return out

    def set_savings_goal(self, amount):
        """Set the group's target leftover budget. Returns the stored goal."""
        if not _is_number(amount):
            raise ValidationError("savings goal must be a real number")
        if amount < 0:
            raise ValidationError("savings goal must be non-negative")
        self._savings_goal = _money(amount)
        return self._savings_goal

    @property
    def savings_goal(self):
        """The current savings goal."""
        return self._savings_goal

    def goal_met(self):
        """True when remaining budget is at least the savings goal."""
        return self.remaining_budget() >= self._savings_goal

    # ----------------------------------------------------------------- #
    # Dashboard
    # ----------------------------------------------------------------- #
    def dashboard(self):
        """Structured summary of the group's financial status."""
        cats = {}
        for key in sorted(self._budgets):
            limit = self._budgets[key]["limit"]
            spent = _money(self._cat_spent.get(key, 0.0))
            cats[self._budgets[key]["name"]] = {
                "limit": limit,
                "spent": spent,
                "remaining": _money(limit - spent),
                "over_budget": spent > limit,
            }
        return {
            "total_budget": self.total_budget(),
            "total_spent": self.total_spent(),
            "remaining": self.remaining_budget(),
            "savings_goal": self._savings_goal,
            "goal_met": self.goal_met(),
            "num_users": len(self._users),
            "categories": cats,
            "contributions": self.member_contributions(),
        }

    def format_dashboard(self):
        """Human-readable rendering of :meth:`dashboard`."""
        data = self.dashboard()
        line = "=" * 52
        out = [line, "BUDGET DASHBOARD", line]
        out.append("Total Budget:    %s" % _fmt_money(data["total_budget"]))
        out.append("Total Spent:     %s" % _fmt_money(data["total_spent"]))
        out.append("Remaining:       %s" % _fmt_money(data["remaining"]))
        out.append("Savings Goal:    %s" % _fmt_money(data["savings_goal"]))
        out.append("Goal Met:        %s" % ("yes" if data["goal_met"] else "no"))
        out.append("Members:         %d" % data["num_users"])
        out.append("")
        out.append("Categories:")
        if data["categories"]:
            for name, info in data["categories"].items():
                flag = "  [OVER]" if info["over_budget"] else ""
                out.append(
                    "  - %-14s spent %s / %s  (remaining %s)%s"
                    % (
                        name,
                        _fmt_money(info["spent"]),
                        _fmt_money(info["limit"]),
                        _fmt_money(info["remaining"]),
                        flag,
                    )
                )
        else:
            out.append("  (none)")
        out.append("")
        out.append("Member Contributions:")
        if data["contributions"]:
            for name, info in data["contributions"].items():
                out.append(
                    "  - %-14s %s  (%.1f%%)"
                    % (name, _fmt_money(info["amount"]), info["share"] * 100.0)
                )
        else:
            out.append("  (none)")
        out.append(line)
        return "\n".join(out)

    # ----------------------------------------------------------------- #
    # Optimization
    # ----------------------------------------------------------------- #
    def optimize(self):
        """Compute reallocation, reduction and savings-goal suggestions.

        Strategy:
          1. Cover over-budget categories by reallocating surplus budget from
             under-spent categories (greedy, largest first).
          2. Overage that surplus cannot fund becomes a spending-reduction
             suggestion for that category.
          3. If a positive savings goal is not met, suggest spending cuts in the
             highest-spending categories to close the gap.
        """
        overages = {}
        surpluses = {}
        for key in self._budgets:
            limit = self._budgets[key]["limit"]
            spent = self._cat_spent.get(key, 0.0)
            diff = _money(spent - limit)
            if diff > 0:
                overages[key] = diff
            elif diff < 0:
                surpluses[key] = _money(-diff)

        total_overage = _money(sum(overages.values()))
        total_surplus = _money(sum(surpluses.values()))

        reallocations = []
        reductions = []
        remaining_surplus = dict(surpluses)

        for ocat in sorted(overages, key=lambda c: overages[c], reverse=True):
            need = overages[ocat]
            for scat in sorted(remaining_surplus, key=lambda c: remaining_surplus[c], reverse=True):
                if need <= 0:
                    break
                avail = remaining_surplus[scat]
                if avail <= 0:
                    continue
                move = _money(min(need, avail))
                if move <= 0:
                    continue
                reallocations.append(
                    {
                        "from": self._budgets[scat]["name"],
                        "to": self._budgets[ocat]["name"],
                        "amount": move,
                    }
                )
                remaining_surplus[scat] = _money(avail - move)
                need = _money(need - move)
            if need > 0:
                reductions.append(
                    {
                        "category": self._budgets[ocat]["name"],
                        "amount": need,
                        "reason": "Insufficient surplus to reallocate; reduce spending",
                    }
                )

        remaining = self.remaining_budget()
        savings_gap = 0.0
        savings_suggestions = []
        if self._savings_goal > 0:
            gap = _money(self._savings_goal - remaining)
            if gap > 0:
                savings_gap = gap
                spenders = sorted(
                    (k for k in self._budgets if self._cat_spent.get(k, 0.0) > 0),
                    key=lambda c: self._cat_spent.get(c, 0.0),
                    reverse=True,
                )
                need = gap
                for key in spenders:
                    if need <= 0:
                        break
                    cut = _money(min(need, self._cat_spent.get(key, 0.0)))
                    if cut <= 0:
                        continue
                    savings_suggestions.append(
                        {
                            "category": self._budgets[key]["name"],
                            "amount": cut,
                            "reason": "Reduce spending to help reach the savings goal",
                        }
                    )
                    need = _money(need - cut)

        messages = []
        if not overages:
            messages.append("All categories are within budget.")
        else:
            if reallocations:
                messages.append("Reallocate surplus budget to cover over-budget categories.")
            if reductions:
                messages.append("Some overages cannot be funded by surplus; reduce spending.")
        if self._savings_goal > 0:
            if savings_gap <= 0:
                messages.append("Savings goal is on track.")
            else:
                messages.append("Savings goal is short by %s." % _fmt_money(savings_gap))

        status = "action_needed" if (overages or savings_gap > 0) else "ok"

        return {
            "status": status,
            "total_budget": self.total_budget(),
            "total_spent": self.total_spent(),
            "remaining": remaining,
            "savings_goal": self._savings_goal,
            "total_overage": total_overage,
            "total_surplus": total_surplus,
            "reallocations": reallocations,
            "reductions": reductions,
            "savings_gap": savings_gap,
            "savings_suggestions": savings_suggestions,
            "messages": messages,
        }

    def format_optimization(self):
        """Human-readable rendering of :meth:`optimize`."""
        report = self.optimize()
        line = "=" * 52
        out = [line, "OPTIMIZATION REPORT", line]
        out.append("Status:         %s" % report["status"])
        out.append("Total Overage:  %s" % _fmt_money(report["total_overage"]))
        out.append("Total Surplus:  %s" % _fmt_money(report["total_surplus"]))
        out.append("Savings Gap:    %s" % _fmt_money(report["savings_gap"]))
        out.append("")
        out.append("Reallocations:")
        if report["reallocations"]:
            for item in report["reallocations"]:
                out.append(
                    "  - move %s from %s to %s"
                    % (_fmt_money(item["amount"]), item["from"], item["to"])
                )
        else:
            out.append("  (none)")
        out.append("")
        out.append("Suggested Reductions:")
        combined = report["reductions"] + report["savings_suggestions"]
        if combined:
            for item in combined:
                out.append(
                    "  - cut %s in %s  (%s)"
                    % (_fmt_money(item["amount"]), item["category"], item["reason"])
                )
        else:
            out.append("  (none)")
        out.append("")
        out.append("Notes:")
        if report["messages"]:
            for msg in report["messages"]:
                out.append("  * %s" % msg)
        else:
            out.append("  (none)")
        out.append(line)
        return "\n".join(out)


