# Comprehensive test suite
# --------------------------------------------------------------------------- #
class TestUserManagement(unittest.TestCase):
    def setUp(self):
        self.opt = MultiAgentBudgetOptimizer()

    def test_add_user(self):
        name = self.opt.add_user("Alice")
        self.assertEqual(name, "Alice")
        self.assertTrue(self.opt.has_user("Alice"))
        self.assertIn("Alice", self.opt.users())

    def test_add_user_strips_whitespace(self):
        name = self.opt.add_user("  Bob  ")
        self.assertEqual(name, "Bob")
        self.assertTrue(self.opt.has_user("Bob"))
        self.assertEqual(self.opt.users(), ["Bob"])

    def test_duplicate_user_rejected(self):
        self.opt.add_user("Alice")
        with self.assertRaises(DuplicateError):
            self.opt.add_user("Alice")

    def test_get_unknown_user_rejected(self):
        with self.assertRaises(NotFoundError):
            self.opt.get_user("Nobody")

    def test_invalid_user_name_rejected(self):
        with self.assertRaises(ValidationError):
            self.opt.add_user("")
        with self.assertRaises(ValidationError):
            self.opt.add_user("   ")

    def test_remove_unknown_user_rejected(self):
        with self.assertRaises(NotFoundError):
            self.opt.remove_user("Ghost")

    def test_remove_user(self):
        self.opt.add_user("Alice")
        removed = self.opt.remove_user("Alice")
        self.assertEqual(removed, "Alice")
        self.assertFalse(self.opt.has_user("Alice"))
        self.assertEqual(self.opt.users(), [])


class TestExpenses(unittest.TestCase):
    def setUp(self):
        self.opt = MultiAgentBudgetOptimizer()
        self.opt.add_user("Alice")
        self.opt.set_budget("Groceries", 200)

    def test_add_expense(self):
        amt = self.opt.add_expense("Alice", "groceries", 50)
        self.assertEqual(amt, 50.0)
        self.assertEqual(self.opt.category_spent("groceries"), 50.0)
        self.assertEqual(self.opt.total_spent(), 50.0)

    def test_category_remaining(self):
        self.opt.add_expense("Alice", "Groceries", 50)
        self.assertEqual(self.opt.category_remaining("groceries"), 150.0)

    def test_expense_invalid_amount_rejected(self):
        with self.assertRaises(ValidationError):
            self.opt.add_expense("Alice", "groceries", 0)
        with self.assertRaises(ValidationError):
            self.opt.add_expense("Alice", "groceries", -5)
        with self.assertRaises(ValidationError):
            self.opt.add_expense("Alice", "groceries", "free")

    def test_expense_unknown_category_rejected(self):
        with self.assertRaises(NotFoundError):
            self.opt.add_expense("Alice", "yachts", 10)

    def test_expense_unknown_user_rejected(self):
        with self.assertRaises(NotFoundError):
            self.opt.add_expense("Zorg", "groceries", 10)

    def test_over_budget_detection(self):
        self.opt.add_expense("Alice", "groceries", 250)
        self.assertTrue(self.opt.is_over_budget("groceries"))
        self.assertEqual(self.opt.category_remaining("groceries"), -50.0)

    def test_rounding_to_cents(self):
        amt = self.opt.add_expense("Alice", "groceries", 10.125)
        self.assertEqual(amt, 10.13)
        self.assertEqual(self.opt.category_spent("groceries"), 10.13)


class TestBudgetManagement(unittest.TestCase):
    def setUp(self):
        self.opt = MultiAgentBudgetOptimizer()

    def test_set_and_get_budget_case_insensitive(self):
        self.opt.set_budget("Groceries", 300)
        self.assertEqual(self.opt.get_budget("groceries"), 300.0)
        self.assertEqual(self.opt.get_budget("GROCERIES"), 300.0)

    def test_set_budget_zero_allowed(self):
        self.opt.set_budget("Misc", 0)
        self.assertEqual(self.opt.get_budget("misc"), 0.0)

    def test_set_budget_negative_rejected(self):
        with self.assertRaises(ValidationError):
            self.opt.set_budget("Rent", -1)

    def test_set_budget_invalid_amount_rejected(self):
        with self.assertRaises(ValidationError):
            self.opt.set_budget("Rent", "lots")

    def test_set_budget_invalid_category_rejected(self):
        with self.assertRaises(ValidationError):
            self.opt.set_budget("   ", 100)

    def test_adjust_budget_up_and_down(self):
        self.opt.set_budget("Food", 100)
        self.assertEqual(self.opt.adjust_budget("food", 50), 150.0)
        self.assertEqual(self.opt.adjust_budget("food", -30), 120.0)
        self.assertEqual(self.opt.get_budget("Food"), 120.0)

    def test_adjust_budget_negative_result_rejected(self):
        self.opt.set_budget("Food", 100)
        with self.assertRaises(ValidationError):
            self.opt.adjust_budget("food", -150)
        self.assertEqual(self.opt.get_budget("food"), 100.0)

    def test_adjust_unknown_category_rejected(self):
        with self.assertRaises(NotFoundError):
            self.opt.adjust_budget("ghost", 10)

    def test_remove_budget(self):
        self.opt.set_budget("Food", 100)
        removed = self.opt.remove_budget("food")
        self.assertEqual(removed, "Food")
        self.assertFalse(self.opt.has_budget("Food"))
        with self.assertRaises(NotFoundError):
            self.opt.get_budget("food")

    def test_remove_unknown_budget_rejected(self):
        with self.assertRaises(NotFoundError):
            self.opt.remove_budget("ghost")

    def test_total_budget(self):
        self.opt.set_budget("Food", 100)
        self.opt.set_budget("Fun", 50)
        self.opt.set_budget("Rent", 850)
        self.assertEqual(self.opt.total_budget(), 1000.0)


class TestDashboardAndViews(unittest.TestCase):
    def setUp(self):
        self.opt = MultiAgentBudgetOptimizer()
        self.opt.add_user("Alice")
        self.opt.add_user("Bob")
        self.opt.set_budget("Groceries", 300)
        self.opt.set_budget("Entertainment", 200)
        self.opt.add_expense("Alice", "Groceries", 120)
        self.opt.add_expense("Bob", "Entertainment", 80)

    def test_totals(self):
        self.assertEqual(self.opt.total_budget(), 500.0)
