    def test_reallocation_fully_covers_overage(self):
        self.opt.set_budget("Food", 100)
        self.opt.set_budget("Fun", 100)
        self.opt.add_expense("Alice", "Food", 150)  # over by 50
        self.opt.add_expense("Alice", "Fun", 30)    # surplus 70
        report = self.opt.optimize()
        self.assertEqual(report["total_overage"], 50.0)
        self.assertTrue(report["reallocations"])
        self.assertEqual(sum(x["amount"] for x in report["reallocations"]), 50.0)
